> 也许您需要提供更多详细信息或演示，以便人们更容易地找到问题。我有一个 demo：[MCP 客户端](https://github.com/sunyuhan1998/spring-ai-repro-demo/tree/main/mcp/mcp-client)和一个使用最新版本的 Spring AI 的演示 [MCP 服务器](https://github.com/sunyuhan1998/spring-ai-repro-demo/tree/main/mcp/mcp-server)，在这个演示中，模型很好地调用了该工具。`1.1.0-SNAPSHOT`

//This is my construction method and the method for calling the model response
//This method works fine in version 1.0.0

public AiController(ChatClient.Builder chatClient, List<McpAsyncClient> mcpASyncClients) {
        this.chatClient = chatClient
                .defaultAdvisors(MessageChatMemoryAdvisor.builder(chatMemory).build())
                .build();
        this.mcpASyncClients = mcpASyncClients;
    }
public Flux<String> chat(@RequestBody GetRequest request) {
        response = chatClient.prompt(multiModalFile)    //Multimodal file, may be empty
                    .system(System_Prompt)        //system prompt value of string
                    .user(userMessage)       //user message value of string 
                    .toolCallbacks(new AsyncMcpToolCallbackProvider(mcpASyncClients))
                    .advisors(a -> a.param(ChatMemory.CONVERSATION_ID, request.getChatId())) 
                    .stream()        
                    .content();  
      return response;
}
